INSERT INTO app_version (version_code, version_name, apk_url, update_log, is_force_update, created_at) VALUES (6, '1.0.6', 'https://apk.xqh.cc.cd/sheeps_1.0.6.apk', '1、修复卡牌回档问题。2、修复其他问题，提升用户体验。', 0, 1783048053840);
INSERT INTO notice (title, title_en, title_ja, title_ko, content, content_en, content_ja, content_ko, type, created_at) VALUES ('v1.0.6 版本更新 / Version Update', 'v1.0.6 version update / Version Update', 'v1.0.6 バージョンアップデート / バージョンアップ', 'v1.0.6 버전 업데이트 / 버전 업데이트', '1、修复卡牌回档问题。2、修复其他问题，提升用户体验。', '1. Fix the issue of card rollback. 2. Fix other problems and improve user experience.', '1. カードのロールバックの問題を修正します。 2. その他の問題を修正し、ユーザー エクスペリエンスを向上させます。', '1. 카드 롤백 문제를 수정합니다. 2. 기타 문제를 수정하고 사용자 경험을 개선합니다.', 'update', 1783048053840);